import{_ as a,o as i,c as n,e as t,a as e,b as r,f as d}from"./app-2959652e.js";const s={},l=e("h2",{id:"最终效果",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#最终效果","aria-hidden":"true"},"#"),r(" 最终效果")],-1),c=e("figure",null,[e("img",{src:"https://gitee.com/muzzik/images/raw/master/blog/article/24/1.png",alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),o=d(`<h2 id="mesh-是什么" tabindex="-1"><a class="header-anchor" href="#mesh-是什么" aria-hidden="true">#</a> Mesh 是什么？</h2><p>我们看到的模型就是网格，网格是由一个个三角面片组成的再经过光栅化才到我们的屏幕上，而切割网格，实际就是切割三角形</p><h2 id="确定切割方向" tabindex="-1"><a class="header-anchor" href="#确定切割方向" aria-hidden="true">#</a> 确定切割方向</h2><p>使用平面来确定切割方向，由于我们获取的网格顶点坐标是模型的本地坐标，所以也需要把创建平面的法线，坐标也转换为模型本地坐标</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>this._plane = cc.geometry.Plane.fromNormalAndPoint(
	new cc.geometry.Plane(),
	// 法线方向
	node_.ui_transform
		.convertToNodeSpaceAR(plane_.ui_transform.convertToWorldSpaceAR(cc.Vec3.UP))
		.subtract(node_.ui_transform.convertToNodeSpaceAR(plane_.worldPosition))
		.normalize(),
	// 平面在切割节点的本地坐标
	node_.ui_transform.convertToNodeSpaceAR(plane_.worldPosition)
);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="获取模型网格" tabindex="-1"><a class="header-anchor" href="#获取模型网格" aria-hidden="true">#</a> 获取模型网格</h2><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>// 获取 cc.Mesh
this._mesh = node_.getComponent(cc.MeshRenderer)!.mesh!;

/** 网格数据 */
const mesh = cc.utils.readMesh(this._mesh, 0);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>注意，这里只是获取的下标为 0 的子网格，如果一个模型包含多个子网格，那么还是需要遍历获取再切割，可以通过 <code>this._mesh.struct.primitives.length</code> 获取子网格数量</p><h2 id="切割三角形" tabindex="-1"><a class="header-anchor" href="#切割三角形" aria-hidden="true">#</a> 切割三角形</h2><p>前面说了切割模型实际就是切换三角形，如何切割？</p><figure><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/2.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><ul><li><strong>(i1, i0)</strong>：平面</li><li><strong>(p0, p1, p2)</strong>：原本的三角形（逆时针为正面）</li><li><strong>(p0, i1, i2)</strong>：切割后的三角形</li><li><strong>(i1, p1, p2)</strong>: 切割后的三角形2</li><li><strong>(i2, i1, p2)</strong>: 切割后的三角形3</li></ul><ol><li>如果三角形三个顶点形成的线段不与平面相交，那么则不需要新建顶点</li><li>如果三角形线段与平面相交，则切割为三个三角形</li></ol><h3 id="_1-确定三角点是否与平面相交" tabindex="-1"><a class="header-anchor" href="#_1-确定三角点是否与平面相交" aria-hidden="true">#</a> 1. 确定三角点是否与平面相交</h3><p>这里我们只需要知道三角形的顶点是否在平面的正面或者反面就可以判断是否相交，<br><strong>如果三个点全在一侧则肯定不相交，如果不全在一侧则一点相交</strong>，我们可以使用点乘 dot 判断在平面的哪一侧</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>positive_b = this._plane.n.dot(p) - this._plane.d &gt;= 0;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_1-确定平面与模型的交点" tabindex="-1"><a class="header-anchor" href="#_1-确定平面与模型的交点" aria-hidden="true">#</a> 1. 确定平面与模型的交点</h3><p>确定 i1 的坐标，从 p0 到 p1 的方向创建一条射线</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>cc.geometry.Ray.fromPoints(ray, p0, p1);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>计算与平面的交点距离</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>const distance_n = cc.geometry.intersect.rayPlane(ray, this._plane);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>获取交点坐标</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>ray.computeHit(point, distance_n);
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="_2-计算新建顶点的uv-法线" tabindex="-1"><a class="header-anchor" href="#_2-计算新建顶点的uv-法线" aria-hidden="true">#</a> 2. 计算新建顶点的uv，法线</h3><p>uv 和 法线的计算很简单，例：p0 - p1 的交点 i1 的法线及 uv 就是 p0 - p1 的法线及 uv 插值交点距离</p><h2 id="生成平面" tabindex="-1"><a class="header-anchor" href="#生成平面" aria-hidden="true">#</a> 生成平面</h2><p>切割网格后会留下空洞，那么如何给它添加一个平面？</p><h3 id="简单的三角剖分方案" tabindex="-1"><a class="header-anchor" href="#简单的三角剖分方案" aria-hidden="true">#</a> 简单的三角剖分方案</h3><ol><li><p>求平均点，不完全支持凹多边形<br><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/3.png" alt="" loading="lazy"></p></li><li><p>左右横跳，不完全支持凹多边形<br><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/4.png" alt="" loading="lazy"></p></li><li><p>单点遍历，不完全支持凹多边形<br><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/5.png" alt="" loading="lazy"></p></li></ol><h3 id="不支持凹面多边形的后果" tabindex="-1"><a class="header-anchor" href="#不支持凹面多边形的后果" aria-hidden="true">#</a> 不支持凹面多边形的后果</h3><p>可以看下图</p><figure><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/6.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这样的话，无论是使用平均点，还是图中的单点遍历新建三角形，都会有可能出现生成的三角形错误的情况</p><p><strong>那么如何做？步骤如下</strong></p><ol><li><p>记录新增的顶点坐标并排序（连线）</p></li><li><p>将排序后的多边形顶点分解为凸多边形</p></li><li><p>为所有凸多边形生成三角形</p></li></ol><h3 id="怎么判断凹凸" tabindex="-1"><a class="header-anchor" href="#怎么判断凹凸" aria-hidden="true">#</a> 怎么判断凹凸？</h3><figure><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/7.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>判断 p0 - p1 - p2 的夹角角度即可，这也是我们需要对新增顶点坐标排序的原因</p><h3 id="将凹多边形分解为凸多边形" tabindex="-1"><a class="header-anchor" href="#将凹多边形分解为凸多边形" aria-hidden="true">#</a> 将凹多边形分解为凸多边形</h3><p>在找到凹角之后，我们只需要从 p1 的位置开始遍历至顶点，只要找到 p0 - p1 - pn 夹角不为凹角的 pn 顶点就可以分割为两个多边形，再对分割后的多边形重复执行此操作</p><h2 id="后记" tabindex="-1"><a class="header-anchor" href="#后记" aria-hidden="true">#</a> 后记</h2><h3 id="平面带孔的情况" tabindex="-1"><a class="header-anchor" href="#平面带孔的情况" aria-hidden="true">#</a> 平面带孔的情况</h3><figure><img src="https://gitee.com/muzzik/images/raw/master/blog/article/24/8.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>将排序后的两个多边形合并为一个，将内多边形的点连接到最近的一个外多边形，组合成为一个单独的多边形</p><p>但是还有一个问题，那就是单独的两个多边形可以依靠法线和碰撞检测来判断当前多边形是否在另一个内，那么多个多边形嵌套呢？</p><p>我这里想到的是使用面积判断，从大到小对多边形排序，内多边形的面积一定比外多边形小</p><h2 id="结语" tabindex="-1"><a class="header-anchor" href="#结语" aria-hidden="true">#</a> 结语</h2><ol><li>不提供源码</li><li>疑问可在群内提问，qq 群：200351945</li></ol>`,48);function h(p,g){return i(),n("div",null,[l,c,t(" more "),o])}const u=a(s,[["render",h],["__file","24.html.vue"]]);export{u as default};
